-- -----------------------------------------------------------------------------
-- File      : tb_swb_cross_ghdl.vhd
-- Purpose   : Scheduled GHDL waveform fixture for MuSiP SWB/OPQ packet evidence.
--
-- The packet streams are read from replay/*.mem files generated by
-- scripts/gen_swb_cross_replay.py. Those files use the same basic-case
-- reference builder that feeds the UVM sequence, so this fixture is a waveform
-- display/replay harness rather than an independent OPQ timing model.
-- -----------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_textio.all;

use std.env.all;
use std.textio.all;

entity tb_swb_cross_ghdl is
generic (
    G_CASE_CYCLES     : positive := 24576;
    G_CLOCK_PERIOD_NS : positive := 4
);
end entity;

architecture sim of tb_swb_cross_ghdl is

    constant C_CLK_PERIOD : time := G_CLOCK_PERIOD_NS * 1 ns;

    subtype t_data_word is std_logic_vector(31 downto 0);
    subtype t_datak_word is std_logic_vector(3 downto 0);
    subtype t_stream_word is std_logic_vector(35 downto 0);
    subtype t_event_word is std_logic_vector(47 downto 0);
    subtype t_word_kind is unsigned(4 downto 0);
    subtype t_header_id is unsigned(5 downto 0);
    subtype t_lane_id is unsigned(1 downto 0);
    subtype t_provenance_id is unsigned(2 downto 0);
    subtype t_halfword is unsigned(15 downto 0);
    subtype t_timestamp is unsigned(47 downto 0);
    subtype t_lane_mask is std_logic_vector(3 downto 0);

    type t_nat4 is array (0 to 3) of natural;
    type t_stream_word4 is array (0 to 3) of t_stream_word;
    type t_ts_state is record
        ts_high : unsigned(31 downto 0);
        ts_low  : unsigned(15 downto 0);
    end record;

    type t_case_cfg is record
        code         : natural;
        bucket       : natural;
        lane_skew    : natural;
        dma_bp_pct   : natural;
        error_path   : boolean;
        csr_activity : boolean;
